mapper.select:
SELECT  
  FROM  TB_MEMO_TODO  A
 WHERE  A.TODO_ID = #{todoId}

mapper.insert:
INSERT  INTO TB_MEMO_TODO
      ( TODO_ID
      , TODO_SJ
      , TODO_CN
      , TODO_BEGIN_TIME
      , TODO_END_TIME
      , WRTER_ID
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{todoId}
        , #{todoNm}
        , #{todoCn}
        , #{todoBeginTime}
        , #{todoEndTime}
        , #{wrterId}
        , #{frstRegisterId}
        , CURRENT_TIMESTAMP )

mapper.update:
UPDATE  TB_MEMO_TODO
   SET  TODO_SJ         = #{todoNm}
      , TODO_CN         = #{todoCn}
      , TODO_BEGIN_TIME = #{todoBeginTime}
      , TODO_END_TIME   = #{todoEndTime}
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  TODO_ID = #{todoId}
